{
  "schema_version": "0.2",
  "mode": "design",
  "workflow_kind": "dynamic",
  "dependencies": {
    "parallel_units": true,
    "edges": [
      {
        "from": "security_check_workers",
        "to": "shared_report_md_sink",
        "type": "mutation",
        "reason": "all 20 workers currently append to the same report.md file, so shared output mutation must be serialized or otherwise mediated before direct writes occur"
      }
    ],
    "capacity_constraints": [
      {
        "resource": "shared_report_md_append_path",
        "limit": "1 concurrent append sequence to report.md",
        "capacity_class": "data_plane_execution",
        "enforcement_owner": "target_data_plane"
      }
    ]
  },
  "dynamic": {
    "batch": {
      "handle": "security_checks_batch",
      "item_identity_source": "route_launch_snapshot"
    },
    "await": {
      "join": "all",
      "k": null,
      "quorum_basis": null,
      "eligible_identity_source": "route_launch_snapshot",
      "eligible_statuses": [
        "succeeded",
        "failed",
        "cancelled",
        "timed_out"
      ],
      "wake_event": "audit_batch_settled"
    },
    "accounting": {
      "expected_identity_source": "route_launch_snapshot",
      "terminal_statuses": [
        "succeeded",
        "failed",
        "cancelled",
        "timed_out"
      ],
      "duplicate_policy": "open",
      "unknown_policy": "open",
      "failure_policy": "open",
      "partial_policy": "open",
      "complete_label_requires": [
        "expected_vs_represented",
        "no_duplicates",
        "no_unknown_identities",
        "terminal_status_accounted",
        "no_unresolved_identities"
      ]
    },
    "reductions": [
      {
        "name": "batch_summary_layer",
        "expected_identity_source": "route_launch_snapshot",
        "observed_result_source": "received_route_result_records",
        "represented_identity_source": "identities_extracted_from_received_route_results",
        "represented_identity_derivation": "from_observed_results",
        "status_count_source": "statuses_from_received_route_results",
        "unresolved_identity_source": "expected_minus_observed_route_identities",
        "output_summary_identity_source": "emitted_batch_summary_manifest"
      }
    ],
    "final_reconciliation": {
      "expected_summary_identity_source": "emitted_batch_summary_manifest",
      "observed_summary_source": "received_batch_summary_records",
      "represented_identity_derivation": "from_observed_summaries",
      "checks": [
        "expected_vs_represented",
        "duplicate",
        "unknown",
        "terminal_status",
        "unresolved"
      ]
    }
  },
  "open_points": [
    {
      "key": "duplicate_policy",
      "question": "If multiple result records are received for the same security check identity, should the control plane reject the batch or allow reconciliation to continue?"
    },
    {
      "key": "unknown_policy",
      "question": "If a result is received for an identity not present in the 20-check launch snapshot, should the control plane reject it or ignore it for completion accounting?"
    },
    {
      "key": "failure_policy",
      "question": "Does any failed, cancelled, or timed_out security check block synthesis of the final report, or may a report still be emitted with those outcomes recorded?"
    },
    {
      "key": "partial_policy",
      "question": "May the workflow emit a partial report when some of the 20 expected security check identities remain unresolved or unrepresented?"
    }
  ],
  "scenarios": [
    {
      "kind": "positive",
      "expected": "All 20 launched security check identities are represented exactly once with terminal statuses, the control plane wakes on audit_batch_settled, emits a complete batch summary manifest, and final reconciliation passes."
    },
    {
      "kind": "missing",
      "expected": "At least one launched security check identity has no observed result record, so reconciliation reports unresolved identities and the batch cannot satisfy the complete label."
    },
    {
      "kind": "duplicate",
      "expected": "A security check identity appears more than once in received_route_result_records, duplicate detection is surfaced in accounting, and downstream completeness depends on the unresolved duplicate_policy."
    },
    {
      "kind": "failed",
      "expected": "One or more security checks reach failed terminal status, the all-items join still wakes once every expected identity is terminal, and final synthesis behavior remains open under failure_policy."
    },
    {
      "kind": "timed_out",
      "expected": "One or more security checks reach timed_out terminal status, the all-items join still wakes once all expected identities are terminal, and final synthesis behavior remains open under failure_policy."
    },
    {
      "kind": "unknown",
      "expected": "A received result record names an identity outside route_launch_snapshot, reconciliation flags an unknown identity, and treatment of that record remains open under unknown_policy."
    },
    {
      "kind": "partial_refused",
      "expected": "If partial_policy is later decided as reject, unresolved or incomplete representation prevents emission of a partial report and leaves only an incomplete accounting outcome."
    },
    {
      "kind": "partial_allowed",
      "expected": "If partial_policy is later decided as allow_incomplete, unresolved or incomplete representation may still permit emission of a partial report with explicit incompleteness recorded."
    },
    {
      "kind": "capacity",
      "expected": "Because all workers currently target the same report.md append path, the shared file mutation path is treated as a data-plane execution bottleneck with single-writer enforcement outside the control plane."
    }
  ],
  "boundary": {
    "control_plane": [
      "launch",
      "await",
      "accounting",
      "reconciliation",
      "control_plane_input_capacity"
    ],
    "target_data_plane": [
      "workers",
      "scheduling",
      "persistence",
      "rate_limiting",
      "backpressure",
      "shared_report_md_write_serialization"
    ]
  }
}

